parameters.jsonBody:
={{ JSON.stringify({
  projectToken: $('AtlasSynapse Config').first().json.ATLAS_PROJECT_TOKEN,
  agentId: $('AtlasSynapse Config').first().json.ATLAS_AGENT_NAME,
  externalTraceId: $execution.id + '-' + Date.now(),
  timestamp: new Date().toISOString(),
  prompt: $('AI Agent').first().json.input?.input || $('AI Agent').first().json.input || $json.chatInput || $json.prompt || 'Hello, how can you help?',
  response: $('AI Agent').first().json.output || '',
  toolCalls: ($('AI Agent').first().json.intermediateSteps || []).map(step => ({
    name: step.action?.tool || 'unknown',
    input: step.action?.toolInput || {},
    output: step.observation ? String(step.observation).slice(0, 5000) : undefined
  })),
  platform: 'n8n'
}) }}
